+package main
+
+import (
+	"encoding/json"
+	"fmt"
+	"log/slog"
+	"os"
+	"path/filepath"
+	"sync"
+	"time"
+
+	"github.com/prometheus/prometheus/config"
+	api_v1 "github.com/prometheus/prometheus/web/api/v1"
+)
+
+const reloadStateFilename = "reload-state.json"
+
+type transactionalReloader struct {
+	mu       sync.RWMutex
+	lastGood *config.Config
+	state    api_v1.ReloadStatus
+	stateFile string
+}
+
+func newTransactionalReloader(storagePath string) *transactionalReloader {
+	t := &transactionalReloader{stateFile: filepath.Join(storagePath, reloadStateFilename)}
+	data, err := os.ReadFile(t.stateFile)
+	if err == nil && json.Unmarshal(data, &t.state) == nil {
+		t.normalize()
+	}
+	return t
+}
+
+func (t *transactionalReloader) normalize() {
+	if t.state.AppliedReloaders == nil { t.state.AppliedReloaders = []string{} }
+	if t.state.ReloaderTimingsMS == nil { t.state.ReloaderTimingsMS = map[string]int64{} }
+}
+
+func (t *transactionalReloader) Status() api_v1.ReloadStatus {
+	t.mu.RLock(); defer t.mu.RUnlock()
+	s := t.state
+	s.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]int64, len(t.state.ReloaderTimingsMS))
+	for k, v := range t.state.ReloaderTimingsMS { s.ReloaderTimingsMS[k] = v }
+	t.normalizeStatus(&s)
+	return s
+}
+
+func (t *transactionalReloader) normalizeStatus(s *api_v1.ReloadStatus) {
+	if s.AppliedReloaders == nil { s.AppliedReloaders = []string{} }
+	if s.ReloaderTimingsMS == nil { s.ReloaderTimingsMS = map[string]int64{} }
+}
+
+func (t *transactionalReloader) record(s api_v1.ReloadStatus) {
+	t.normalizeStatus(&s)
+	t.mu.Lock(); t.state = s; t.mu.Unlock()
+	data, err := json.Marshal(s)
+	if err != nil { return }
+	if err := os.MkdirAll(filepath.Dir(t.stateFile), 0o755); err != nil { return }
+	tmp := t.stateFile + ".tmp"
+	if os.WriteFile(tmp, data, 0o600) == nil { _ = os.Rename(tmp, t.stateFile) }
+}
+
+// apply applies a loaded config sequentially. Startup establishes the rollback baseline but is not recorded.
+func (t *transactionalReloader) apply(conf *config.Config, rls []reloader, startup bool, logger *slog.Logger) error {
+	s := api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339), AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+	for _, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		s.ReloaderTimingsMS[rl.name] = time.Since(start).Milliseconds()
+		if err == nil { s.AppliedReloaders = append(s.AppliedReloaders, rl.name); continue }
+		s.LastReloadSuccessful, s.ErrorCategory, s.ErrorMessage, s.FailedReloader = false, "apply_error", err.Error(), rl.name
+		if len(s.AppliedReloaders) > 0 && t.lastGood != nil {
+			s.RollbackAttempted, s.RollbackSuccessful = true, true
+			for i := len(s.AppliedReloaders)-1; i >= 0; i-- {
+				name := s.AppliedReloaders[i]
+				for _, old := range rls { if old.name == name { if e := old.reloader(t.lastGood); e != nil { s.RollbackSuccessful = false; s.ErrorCategory = "rollback_error"; s.ErrorMessage = e.Error() }; break } }
+			}
+		}
+		if !startup { t.record(s) }
+		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+	}
+	t.lastGood = conf
+	if !startup { s.LastReloadSuccessful, s.ErrorCategory = true, "none"; t.record(s) }
+	logger.Info("Completed transactional configuration reload")
+	return nil
+}
